std::tuple<int, int, int> test_batch_execution(int initialA,
                                               int initialB,
                                               int nonBatchA,
                                               int nonBatchB,
                                               int batchA,
                                               int batchB) {
    using namespace reaction;

    auto varA = var(initialA);
    auto varB = var(initialB);

    int recomputeCount = 0;

    auto sumCalc = calc([&](int x, int y) {
        ++recomputeCount;
        return x + y;
    }, varA, varB);

