    // Batch updates should trigger recompute only once for both changes
    auto updateBatch = batch([&] {
        varA.value(batchA);
        varB.value(batchB);
    });
    updateBatch.execute();
    const int countAfterBatch = recomputeCount;

    return {sumCalc.get(), countAfterNonBatch, countAfterBatch};
}

